/// Enumerate the type of slice mode
enum SliceModeEnum {
  /// | SliceNum==1
  SM_SINGLE_SLICE(0),

  /// | according to SliceNum | enabled dynamic slicing for multi-thread
  SM_FIXEDSLCNUM_SLICE(1),

  /// | according to SlicesAssign | need input of MB numbers each slice. In
  /// addition, if other constraint in SSliceArgument is presented, need to
  /// follow the constraints. Typically if MB num and slice size are both
  /// constrained, re-encoding may be involved.
  SM_RASTER_SLICE(2),

  /// | according to SliceSize | slicing according to size, the slicing will be
  /// dynamic(have no idea about slice_nums until encoding current frame)
  SM_SIZELIMITED_SLICE(3),
  SM_RESERVED(4);

  final int value;
  const SliceModeEnum(this.value);

  static SliceModeEnum fromValue(int value) => switch (value) {
