  /// only used when uiSliceMode=1, when uiSliceNum=0 means auto design it with
  /// cpu core number
  @ffi.UnsignedInt()
  external int uiSliceNum;

  /// only used when uiSliceMode=2; when =0 means setting one MB row a slice
  @ffi.Array.multi([35])
  external ffi.Array<ffi.UnsignedInt> uiSliceMbNum;

  /// now only used when uiSliceMode=4
  @ffi.UnsignedInt()
  external int uiSliceSizeConstraint;
}

