/// Structure for spatial layer configuration
final class SSpatialLayerConfig extends ffi.Struct {
  /// width of picture in luminance samples of a layer
  @ffi.Int()
  external int iVideoWidth;

  /// height of picture in luminance samples of a layer
  @ffi.Int()
  external int iVideoHeight;

  /// frame rate specified for a layer
  @ffi.Float()
  external double fFrameRate;

  /// target bitrate for a spatial layer, in unit of bps
  @ffi.Int()
  external int iSpatialBitrate;

  /// maximum bitrate for a spatial layer, in unit of bps
  @ffi.Int()
  external int iMaxSpatialBitrate;

  /// value of profile IDC (PRO_UNKNOWN for auto-detection)
  @ffi.UnsignedInt()
  external int uiProfileIdcAsInt;

  EProfileIdc get uiProfileIdc => EProfileIdc.fromValue(uiProfileIdcAsInt);

  /// value of profile IDC (0 for auto-detection)
  @ffi.UnsignedInt()
  external int uiLevelIdcAsInt;

  ELevelIdc get uiLevelIdc => ELevelIdc.fromValue(uiLevelIdcAsInt);

  /// value of level IDC (0 for auto-detection)
  @ffi.Int()
  external int iDLayerQp;

  external SSliceArgument sSliceArgument;

  /// false => do not write any of the following information to the header
  @ffi.Bool()
  external bool bVideoSignalTypePresent;

  /// EVideoFormatSPS; 3 bits in header; 0-5 => component, kpal, ntsc, secam,
  /// mac, undef
  @ffi.UnsignedChar()
  external int uiVideoFormat;

  /// false => analog video data range [16, 235]; true => full data range
  /// [0,255]
  @ffi.Bool()
  external bool bFullRange;

  /// false => do not write any of the following three items to the header
  @ffi.Bool()
  external bool bColorDescriptionPresent;

  /// EColorPrimaries; 8 bits in header; 0 - 9 => ???, bt709, undef, ???,
  /// bt470m, bt470bg,
  @ffi.UnsignedChar()
  external int uiColorPrimaries;

  /// ETransferCharacteristics; 8 bits in header; 0 - 15 => ???, bt709, undef,
  /// ???, bt470m, bt470bg, smpte170m,
  @ffi.UnsignedChar()
  external int uiTransferCharacteristics;

  /// EColorMatrix; 8 bits in header (corresponds to FFmpeg "colorspace"); 0 -
  /// 10 => GBR, bt709,
  @ffi.UnsignedChar()
  external int uiColorMatrix;

  /// aspect ratio present in VUI
  @ffi.Bool()
  external bool bAspectRatioPresent;

  /// aspect ratio idc
  @ffi.UnsignedInt()
  external int eAspectRatioAsInt;

  ESampleAspectRatio get eAspectRatio =>
      ESampleAspectRatio.fromValue(eAspectRatioAsInt);

  /// use if aspect ratio idc == 255
  @ffi.UnsignedShort()
  external int sAspectRatioExtWidth;

  /// use if aspect ratio idc == 255
  @ffi.UnsignedShort()
  external int sAspectRatioExtHeight;
}

