/// SVC Encoding Parameters
final class TagEncParamBase extends ffi.Struct {
  /// application type; please refer to the definition of EUsageType
  @ffi.UnsignedInt()
  external int iUsageTypeAsInt;

  EUsageType get iUsageType => EUsageType.fromValue(iUsageTypeAsInt);

  /// width of picture in luminance samples (the maximum of all layers if
  /// multiple spatial layers presents)
  @ffi.Int()
  external int iPicWidth;

  /// height of picture in luminance samples((the maximum of all layers if
  /// multiple spatial layers presents)
  @ffi.Int()
  external int iPicHeight;

  /// target bitrate desired, in unit of bps
  @ffi.Int()
  external int iTargetBitrate;

  /// rate control mode
  @ffi.Int()
  external int iRCModeAsInt;

  RC_MODES get iRCMode => RC_MODES.fromValue(iRCModeAsInt);

  /// maximal input frame rate
  @ffi.Float()
  external double fMaxFrameRate;
}

/// SVC Encoding Parameters
typedef SEncParamBase = TagEncParamBase;
typedef PEncParamBase = ffi.Pointer<TagEncParamBase>;

/// SVC Encoding Parameters extention
final class TagEncParamExt extends ffi.Struct {
  /// same as in TagEncParamBase
  @ffi.UnsignedInt()
  external int iUsageTypeAsInt;

  EUsageType get iUsageType => EUsageType.fromValue(iUsageTypeAsInt);

  /// same as in TagEncParamBase
  @ffi.Int()
  external int iPicWidth;

  /// same as in TagEncParamBase
  @ffi.Int()
  external int iPicHeight;

  /// same as in TagEncParamBase
  @ffi.Int()
  external int iTargetBitrate;

  /// same as in TagEncParamBase
  @ffi.Int()
  external int iRCModeAsInt;

  RC_MODES get iRCMode => RC_MODES.fromValue(iRCModeAsInt);

  /// same as in TagEncParamBase
  @ffi.Float()
  external double fMaxFrameRate;

  /// temporal layer number, max temporal layer = 4
  @ffi.Int()
  external int iTemporalLayerNum;

  /// spatial layer number,1<= iSpatialLayerNum <= MAX_SPATIAL_LAYER_NUM,
  /// MAX_SPATIAL_LAYER_NUM = 4
  @ffi.Int()
  external int iSpatialLayerNum;

  @ffi.Array.multi([4])
  external ffi.Array<SSpatialLayerConfig> sSpatialLayers;

  @ffi.UnsignedInt()
  external int iComplexityModeAsInt;

  ECOMPLEXITY_MODE get iComplexityMode =>
      ECOMPLEXITY_MODE.fromValue(iComplexityModeAsInt);

  /// period of Intra frame
  @ffi.UnsignedInt()
  external int uiIntraPeriod;

  /// number of reference frame used
  @ffi.Int()
  external int iNumRefFrame;

  /// different stategy in adjust ID in SPS/PPS: 0- constant ID, 1-additional
  /// ID, 6-mapping and additional
  @ffi.UnsignedInt()
  external int eSpsPpsIdStrategyAsInt;

  EParameterSetStrategy get eSpsPpsIdStrategy =>
      EParameterSetStrategy.fromValue(eSpsPpsIdStrategyAsInt);

  /// false:not use Prefix NAL; true: use Prefix NAL
  @ffi.Bool()
  external bool bPrefixNalAddingCtrl;

  /// false:not use SSEI; true: use SSEI -- TODO: planning to remove the
  /// interface of SSEI
  @ffi.Bool()
  external bool bEnableSSEI;

  /// (when encoding more than 1 spatial layer) false: use SVC syntax for higher
  /// layers; true: use Simulcast AVC
  @ffi.Bool()
  external bool bSimulcastAVC;

  /// 0:disable padding;1:padding
  @ffi.Int()
  external int iPaddingFlag;

  /// 0:CAVLC 1:CABAC.
  @ffi.Int()
  external int iEntropyCodingModeFlag;

  /// False: don't skip frame even if VBV buffer overflow.True: allow skipping
  /// frames to keep the bitrate within limits
  @ffi.Bool()
  external bool bEnableFrameSkip;

  /// the maximum bitrate, in unit of bps, set it to UNSPECIFIED_BIT_RATE if not
  /// needed
  @ffi.Int()
  external int iMaxBitrate;

  /// the maximum QP encoder supports
  @ffi.Int()
  external int iMaxQp;

  /// the minmum QP encoder supports
  @ffi.Int()
  external int iMinQp;

  /// the maximum NAL size. This value should be not 0 for dynamic slice mode
  @ffi.UnsignedInt()
  external int uiMaxNalSize;

  /// 1: on, 0: off
  @ffi.Bool()
  external bool bEnableLongTermReference;

  /// the number of LTR(long term reference),TODO: not supported to set it
  /// arbitrary yet
  @ffi.Int()
  external int iLTRRefNum;

  /// the LTR marked period that is used in feedback.
  @ffi.UnsignedInt()
  external int iLtrMarkPeriod;

  /// 1 # 0: auto(dynamic imp. internal encoder); 1: multiple threads imp.
  /// disabled; lager than 1: count number of threads;
  @ffi.UnsignedShort()
  external int iMultipleThreadIdc;

  /// only used when uiSliceMode=1 or 3, will change slicing of a picture during
  /// the run-time of multi-thread encoding, so the result of each run may be
  /// different
  @ffi.Bool()
  external bool bUseLoadBalancing;

  /// 0: on, 1: off, 2: on except for slice boundaries
  @ffi.Int()
  external int iLoopFilterDisableIdc;

  /// AlphaOffset: valid range [-6, 6], default 0
  @ffi.Int()
  external int iLoopFilterAlphaC0Offset;

  /// BetaOffset: valid range [-6, 6], default 0
  @ffi.Int()
  external int iLoopFilterBetaOffset;

  /// denoise control
  @ffi.Bool()
  external bool bEnableDenoise;

  /// background detection control //VAA_BACKGROUND_DETECTION //BGD cmd
  @ffi.Bool()
  external bool bEnableBackgroundDetection;

  /// adaptive quantization control
  @ffi.Bool()
  external bool bEnableAdaptiveQuant;

  /// enable frame cropping flag: TRUE always in application
  @ffi.Bool()
  external bool bEnableFrameCroppingFlag;

  @ffi.Bool()
  external bool bEnableSceneChangeDetect;

  /// LTR advanced setting
  @ffi.Bool()
  external bool bIsLosslessLink;

  /// fix rate control overshooting
  @ffi.Bool()
  external bool bFixRCOverShoot;

  /// the target bits of IDR is (idr_bitrate_ratio/100) * average target bit per
  /// frame.
  @ffi.Int()
  external int iIdrBitrateRatio;
}

/// SVC Encoding Parameters extention
typedef SEncParamExt = TagEncParamExt;

/// Define a new struct to show the property of video bitstream.
final class SVideoProperty extends ffi.Struct {
  /// size of the struct
  @ffi.UnsignedInt()
  external int size;

  /// video stream type (AVC/SVC)
  @ffi.UnsignedInt()
  external int eVideoBsTypeAsInt;

  VIDEO_BITSTREAM_TYPE get eVideoBsType =>
      VIDEO_BITSTREAM_TYPE.fromValue(eVideoBsTypeAsInt);
}

/// SVC Decoding Parameters, reserved here and potential applicable in the
/// future
final class TagSVCDecodingParam extends ffi.Struct {
  /// file name of reconstructed frame used for PSNR calculation based debug
  external ffi.Pointer<ffi.Char> pFileNameRestructed;

  /// CPU load
  @ffi.UnsignedInt()
  external int uiCpuLoad;

  /// setting target dq layer id
  @ffi.UnsignedChar()
  external int uiTargetDqLayer;

  /// whether active error concealment feature in decoder
  @ffi.UnsignedInt()
  external int eEcActiveIdcAsInt;

  ERROR_CON_IDC get eEcActiveIdc => ERROR_CON_IDC.fromValue(eEcActiveIdcAsInt);

  /// decoder for parse only, no reconstruction. When it is true, SPS/PPS size
  /// should not exceed SPS_PPS_BS_SIZE (128). Otherwise, it will return error
  /// info
  @ffi.Bool()
  external bool bParseOnly;

  /// video stream property
  external SVideoProperty sVideoProperty;
}

/// SVC Decoding Parameters, reserved here and potential applicable in the
/// future
typedef SDecodingParam = TagSVCDecodingParam;
typedef PDecodingParam = ffi.Pointer<TagSVCDecodingParam>;

/// Bitstream inforamtion of a layer being encoded
final class SLayerBSInfo extends ffi.Struct {
  @ffi.UnsignedChar()
  external int uiTemporalId;

  @ffi.UnsignedChar()
  external int uiSpatialId;

  @ffi.UnsignedChar()
  external int uiQualityId;

  @ffi.UnsignedInt()
  external int eFrameTypeAsInt;

  EVideoFrameType get eFrameType => EVideoFrameType.fromValue(eFrameTypeAsInt);

  @ffi.UnsignedChar()
  external int uiLayerType;

  /// refer to D.2.11 Sub-sequence information SEI message semantics
  @ffi.Int()
  external int iSubSeqId;

  /// count number of NAL coded already
  @ffi.Int()
  external int iNalCount;

  /// length of NAL size in byte from 0 to iNalCount-1
  external ffi.Pointer<ffi.Int> pNalLengthInByte;

  /// buffer of bitstream contained
  external ffi.Pointer<ffi.UnsignedChar> pBsBuf;
}

/// Bitstream inforamtion of a layer being encoded
typedef PLayerBSInfo = ffi.Pointer<SLayerBSInfo>;

/// Frame bit stream info
final class SFrameBSInfo extends ffi.Struct {
  @ffi.Int()
  external int iLayerNum;

  @ffi.Array.multi([128])
  external ffi.Array<SLayerBSInfo> sLayerInfo;

  @ffi.UnsignedInt()
  external int eFrameTypeAsInt;

  EVideoFrameType get eFrameType => EVideoFrameType.fromValue(eFrameTypeAsInt);

  @ffi.Int()
  external int iFrameSizeInBytes;

  @ffi.LongLong()
  external int uiTimeStamp;
}

/// Frame bit stream info
typedef PFrameBSInfo = ffi.Pointer<SFrameBSInfo>;

/// Structure for source picture
final class Source_Picture_s extends ffi.Struct {
  /// color space type
