  /// plane pData
  @ffi.Array.multi([4])
  external ffi.Array<ffi.Pointer<ffi.UnsignedChar>> pData;

  /// luma picture width in x coordinate
  @ffi.Int()
  external int iPicWidth;

  /// luma picture height in y coordinate
  @ffi.Int()
  external int iPicHeight;

  /// timestamp of the source picture, unit: millisecond
  @ffi.LongLong()
  external int uiTimeStamp;
}

/// Structure for source picture
typedef SSourcePicture = Source_Picture_s;

