}

/// The capability of decoder, for SDP negotiation
typedef SDecoderCapability = TagDecoderCapability;

/// Structure for parse only output
final class TagParserBsInfo extends ffi.Struct {
  /// total NAL number in current AU
  @ffi.Int()
  external int iNalNum;

  /// each nal length
  external ffi.Pointer<ffi.Int> pNalLenInByte;

  /// outputted dst buffer for parsed bitstream
  external ffi.Pointer<ffi.UnsignedChar> pDstBuff;

  /// required SPS width info
