}

/// Structure for parse only output
typedef SParserBsInfo = TagParserBsInfo;
typedef PParserBsInfo = ffi.Pointer<TagParserBsInfo>;

/// Structure for encoder statistics
final class TagVideoEncoderStatistics extends ffi.Struct {
  /// the width of encoded frame
  @ffi.UnsignedInt()
  external int uiWidth;

  /// the height of encoded frame
  @ffi.UnsignedInt()
  external int uiHeight;

  /// average_Encoding_Time
  @ffi.Float()
  external double fAverageFrameSpeedInMs;

  /// the average frame rate in, calculate since encoding starts, supposed that
  /// the input timestamp is in unit of ms
  @ffi.Float()
  external double fAverageFrameRate;

  /// the frame rate in, in the last second, supposed that the input timestamp
  /// is in unit of ms (? useful for checking BR, but is it easy to calculate?
  @ffi.Float()
  external double fLatestFrameRate;

  /// sendrate in Bits per second, calculated within the set time-window
  @ffi.UnsignedInt()
  external int uiBitRate;

  /// the average QP of last encoded frame
  @ffi.UnsignedInt()
  external int uiAverageFrameQP;

  /// number of frames
  @ffi.UnsignedInt()
  external int uiInputFrameCount;

  /// number of frames
  @ffi.UnsignedInt()
  external int uiSkippedFrameCount;

  /// uiResolutionChangeTimes
  @ffi.UnsignedInt()
  external int uiResolutionChangeTimes;

  /// number of IDR requests
  @ffi.UnsignedInt()
  external int uiIDRReqNum;

  /// number of actual IDRs sent
  @ffi.UnsignedInt()
  external int uiIDRSentNum;

  /// number of LTR sent/marked
  @ffi.UnsignedInt()
  external int uiLTRSentNum;

  /// Timestamp of updating the statistics
  @ffi.LongLong()
  external int iStatisticsTs;

  @ffi.UnsignedLong()
  external int iTotalEncodedBytes;

  @ffi.UnsignedLong()
  external int iLastStatisticsBytes;

  @ffi.UnsignedLong()
  external int iLastStatisticsFrameCount;
}

/// Structure for encoder statistics
typedef SEncoderStatistics = TagVideoEncoderStatistics;

/// Structure for decoder statistics
final class TagVideoDecoderStatistics extends ffi.Struct {
  /// the width of encode/decode frame
  @ffi.UnsignedInt()
  external int uiWidth;

  /// the height of encode/decode frame
  @ffi.UnsignedInt()
  external int uiHeight;

  /// average_Decoding_Time
  @ffi.Float()
  external double fAverageFrameSpeedInMs;

  /// actual average_Decoding_Time, including freezing pictures
  @ffi.Float()
  external double fActualAverageFrameSpeedInMs;

  /// number of frames
  @ffi.UnsignedInt()
  external int uiDecodedFrameCount;

  /// uiResolutionChangeTimes
  @ffi.UnsignedInt()
  external int uiResolutionChangeTimes;

  /// number of correct IDR received
  @ffi.UnsignedInt()
  external int uiIDRCorrectNum;

  /// when EC is on, the average ratio of total EC areas, can be an indicator of
  /// reconstruction quality
  @ffi.UnsignedInt()
  external int uiAvgEcRatio;

  /// when EC is on, the rough average ratio of propogate EC areas, can be an
  /// indicator of reconstruction quality
  @ffi.UnsignedInt()
  external int uiAvgEcPropRatio;

  /// number of actual unintegrity IDR or not received but eced
  @ffi.UnsignedInt()
  external int uiEcIDRNum;

  @ffi.UnsignedInt()
  external int uiEcFrameNum;

  /// number of whole lost IDR
  @ffi.UnsignedInt()
  external int uiIDRLostNum;

  /// number of freezing IDR with error (partly received), under resolution
  /// change
  @ffi.UnsignedInt()
  external int uiFreezingIDRNum;

  /// number of freezing non-IDR with error
  @ffi.UnsignedInt()
  external int uiFreezingNonIDRNum;

  /// average luma QP. default: -1, no correct frame outputted
  @ffi.Int()
  external int iAvgLumaQp;

  /// number of Sps Invalid report
  @ffi.Int()
  external int iSpsReportErrorNum;

  /// number of SubSps Invalid report
  @ffi.Int()
  external int iSubSpsReportErrorNum;

  /// number of Pps Invalid report
  @ffi.Int()
  external int iPpsReportErrorNum;

  /// number of Sps NoExist Nal
  @ffi.Int()
  external int iSpsNoExistNalNum;

  /// number of SubSps NoExist Nal
  @ffi.Int()
  external int iSubSpsNoExistNalNum;

  /// number of Pps NoExist Nal
  @ffi.Int()
  external int iPpsNoExistNalNum;

  /// Profile idc in syntax
  @ffi.UnsignedInt()
  external int uiProfile;

  /// level idc according to Annex A-1
  @ffi.UnsignedInt()
  external int uiLevel;

  /// current active SPS id
  @ffi.Int()
  external int iCurrentActiveSpsId;

  /// current active PPS id
  @ffi.Int()
  external int iCurrentActivePpsId;

  /// frame interval of statistics log
  @ffi.UnsignedInt()
  external int iStatisticsLogInterval;
}

/// Structure for decoder statistics
typedef SDecoderStatistics = TagVideoDecoderStatistics;

